export function isInternalModel(id: string): boolean {
  return id.includes('internal') || id.startsWith('accounts/');
}

export function filterModels<T extends { id: string }>(models: T[], hideInternal: boolean): T[] {
  if (!hideInternal) return models;
  return models.filter(m => !isInternalModel(m.id));
}

import { isInternalModel, filterModels } from './filter-models';

describe('isInternalModel', () => {
  it('returns true for IDs containing "internal"', () => {
    expect(isInternalModel('gpt-internal-v1')).toBe(true);
  });

  it('returns true for IDs starting with "accounts/"', () => {
    expect(isInternalModel('accounts/my-org/model')).toBe(true);
  });

  it('returns true for IDs matching both conditions', () => {
    expect(isInternalModel('accounts/internal-org/model')).toBe(true);
  });

  it('returns false for normal IDs', () => {
    expect(isInternalModel('gpt-4o')).toBe(false);
  });
});

describe('filterModels', () => {
  const models = [
    { id: 'gpt-4o' },
    { id: 'internal-preview' },
    { id: 'accounts/org/custom' },
  ];

  it('returns all models when hideInternal is false', () => {
    expect(filterModels(models, false)).toHaveLength(3);
  });

  it('filters internal and account-scoped models when hideInternal is true', () => {
    const result = filterModels(models, true);
    expect(result).toHaveLength(1);
    expect(result[0].id).toBe('gpt-4o');
  });
});

